// ── Cursor ─────────────────────────────────────────────────────────────────────
const Cursor = () => {
  const [pos, setPos] = useState({ x: -100, y: -100 });
  const [hov, setHov] = useState(false);
  useEffect(() => {
    const m = (e) => setPos({ x: e.clientX, y: e.clientY });
    const ov = (e) => setHov(!!e.target.closest("a,button,[data-hover]"));
    window.addEventListener("mousemove", m);
    window.addEventListener("mouseover", ov);
    return () => { window.removeEventListener("mousemove", m); window.removeEventListener("mouseover", ov); };
  }, []);
  const spring = { type:"spring", stiffness:500, damping:35 };
  const trail  = { type:"spring", stiffness:150, damping:22 };
  return (
    <>
      <motion.div style={{ position:"fixed",top:0,left:0,zIndex:99998,pointerEvents:"none" }}
        animate={{ x: pos.x - 20, y: pos.y - 20 }} transition={trail}>
        <div style={{ width:40,height:40,borderRadius:"50%",border:`1.5px solid ${hov?"rgba(184,146,74,0.7)":"rgba(184,146,74,0.3)"}`,transition:"border-color 0.3s, transform 0.3s",transform:hov?"scale(1.7)":"scale(1)" }} />
      </motion.div>
      <motion.div style={{ position:"fixed",top:0,left:0,zIndex:99999,pointerEvents:"none" }}
        animate={{ x: pos.x - 4, y: pos.y - 4 }} transition={spring}>
        <div style={{ width:8,height:8,borderRadius:"50%",background:hov?"#b8924a":"#d4aa6a",boxShadow:"0 0 10px rgba(184,146,74,0.6)" }} />
      </motion.div>
    </>
  );
};

// ── Scroll Progress ────────────────────────────────────────────────────────────
const ScrollProgress = () => {
  const { scrollYProgress } = useScroll();
  const scaleX = useSpring(scrollYProgress, { stiffness:100, damping:30 });
  return (
    <motion.div style={{
      position:"fixed",top:0,left:0,right:0,height:2,
      background:"linear-gradient(90deg,#b8924a,#d4aa6a,#b8924a)",
      transformOrigin:"0%", scaleX, zIndex:10001,
      boxShadow:"0 0 8px rgba(184,146,74,0.6)",
    }} />
  );
};

// ── Loader ─────────────────────────────────────────────────────────────────────
const Loader = ({ onDone }) => {
  const [p, setP] = useState(0);
  useEffect(() => {
    const t = setInterval(() => setP(v => { if(v>=100){clearInterval(t);setTimeout(onDone,300);return 100;} return v+Math.random()*14; }), 55);
    return () => clearInterval(t);
  }, [onDone]);
  return (
    <motion.div exit={{ opacity:0 }} transition={{ duration:0.6 }}
      style={{ position:"fixed",inset:0,background:"#07070a",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",zIndex:100000,gap:"2rem" }}>
      <div style={{ textAlign:"center" }}>
        <div style={{ fontSize:"2.8rem",fontWeight:800,letterSpacing:"-0.02em",fontFamily:"Poppins,sans-serif",background:"linear-gradient(135deg,#b8924a,#d4aa6a)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",marginBottom:"0.3rem" }}>RJ</div>
        <div style={{ fontSize:"0.65rem",letterSpacing:"0.35em",color:"rgba(240,237,232,0.35)",fontFamily:"Poppins,sans-serif" }}>RAVI JUNEJA</div>
      </div>
      <div style={{ width:180,height:1,background:"rgba(255,255,255,0.08)",borderRadius:1,overflow:"hidden" }}>
        <motion.div style={{ height:"100%",background:"linear-gradient(90deg,#b8924a,#d4aa6a)",transformOrigin:"0%" }}
          animate={{ scaleX: Math.min(p,100)/100 }} transition={{ duration:0.1 }} />
      </div>
      <div style={{ fontSize:"0.65rem",color:"rgba(240,237,232,0.25)",fontFamily:"Poppins,sans-serif",letterSpacing:"0.2em" }}>{Math.round(Math.min(p,100))}%</div>
    </motion.div>
  );
};

// ── Reveal ─────────────────────────────────────────────────────────────────────
const Reveal = ({ children, delay=0, y=40 }) => {
  const ref = useRef(null);
  const inView = useInView(ref, { once:true, margin:"-70px" });
  return (
    <motion.div ref={ref} initial={{ opacity:0, y }} animate={inView?{opacity:1,y:0}:{}} transition={{ duration:0.8,delay,ease:[0.23,1,0.32,1] }}>
      {children}
    </motion.div>
  );
};

// ── Counter ────────────────────────────────────────────────────────────────────
const Counter = ({ target, suffix="" }) => {
  const [v, setV] = useState(0);
  const ref = useRef(null);
  const inView = useInView(ref, { once:true });
  useEffect(() => {
    if(!inView) return;
    let s=0; const step=target/120;
    const t = setInterval(() => { s+=step; if(s>=target){setV(target);clearInterval(t);}else setV(Math.floor(s)); }, 16);
    return ()=>clearInterval(t);
  }, [inView, target]);
  return <span ref={ref}>{v}{suffix}</span>;
};

